// Flatten grouped results: each company has multiple jobs
const results = [];

for (const item of $input.all()) {
  const company = item.json.company || {};
  const jobs = item.json.jobs || [];

  for (const job of jobs) {
    // Filter for CX-relevant roles
    const titleLower = (job.title || '').toLowerCase();
    const isCxRelevant = 
      titleLower.includes('customer') ||
      titleLower.includes('support') ||
      titleLower.includes('success') ||
      titleLower.includes('experience') ||
      titleLower.includes('cx') ||
      titleLower.includes('service') ||
      titleLower.includes('solutions') ||
      titleLower.includes('implementation') ||
      titleLower.includes('onboarding') ||
      titleLower.includes('account manager') ||
      titleLower.includes('technical account');

    // Skip non-CX roles to reduce noise
    if (!isCxRelevant) continue;

    // Extract salary if available
    let salaryText = '';
    if (job.salary && job.salary.minValue) {
      const min = job.salary.minValue.toLocaleString();
      const max = job.salary.maxValue ? job.salary.maxValue.toLocaleString() : min;
      const currency = job.salary.currency?.value || 'USD';
      salaryText = `${currency} ${min} - ${max}`;
    }

    // Extract location
    const location = (job.locations || []).filter(l => l).join(', ') || 'Remote';

    results.push({
      json: {
        // Job fields - use pipeline-expected names
        'Job Title': job.title,
        'Job URL': job.applyUrl,
        'Company': company.name,
        'Location': location,
        'Salary': salaryText,
        'Department': (job.departments || []).join(', '),

        // Pre-enriched company data
        'Company Description': company.description,
        'Company Domain': company.domain,
        'Company Website': company.website?.url || `https://${company.domain}`,
        'Employee Count': company.staffCount,
        'Markets': (company.markets || []).join(', '),
        'Investors': (company.investors || []).join(', '),
        'Stage': (company.stages || []).join(', '),
        'Office Locations': (company.officeLocations || []).join(', '),

        // Source tracking
        'Source': 'First Round Jobs',
        'Source Detail': 'first-round-capital'
      }
    });
  }
}

return results;
